from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetMediaVersionsNode(BaseNode):
    name = "Prism: Get Media Versions"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("media_identifier", "any")
        self.add_output("versions", "list")
        self.add_output("latest", "any")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        ident = inputs.get('media_identifier')
        if core is None or ident is None:
            self.log_error("No PrismCore or media_identifier provided.")
            return {'versions': [], 'latest': None, 'count': 0}
        try:
            media_module = getattr(core, 'mediaProducts', None) or getattr(core, 'media', None)
            versions = []
            for attr in ('getVersionsFromIdentifier', 'getMediaVersions', 'getVersions'):
                if hasattr(media_module, attr):
                    versions = getattr(media_module, attr)(ident) or []
                    break
            versions = list(versions)
            latest = versions[-1] if versions else None
            self.log_info(f"Found {len(versions)} media version(s).")
            return {'versions': versions, 'latest': latest, 'count': len(versions)}
        except Exception as e:
            self.log_error(f"getMediaVersions failed: {e}")
            return {'versions': [], 'latest': None, 'count': 0}

def register_node():
    return PrismGetMediaVersionsNode
